class SignedSoapMessageParser {

    private static final String WSSE_NS =
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String DS_NS = javax.xml.crypto.dsig.XMLSignature.XMLNS;

    public static SignedSoapExtraction extractAndVerify(SOAPMessageContext context) {
        try {
            SOAPMessage soapMessage = context.getMessage();
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            soapMessage.writeTo(baos);
            String xml = baos.toString(StandardCharsets.UTF_8.name());

            Document document = parse(xml);
            SignedSoapExtraction extraction = new SignedSoapExtraction();
            extraction.setRawSoapXml(xml);

            Principal principal = (Principal) context.get(MessageContext.SERVLET_REQUEST) != null
                    ? null : null;
            if (principal != null) {
                extraction.setPrincipalName(principal.getName());
            }

            List<Element> signatureElements = findSignatureElements(document);
            if (signatureElements.isEmpty()) {
                extraction.setSignatureVerified(false);
                return extraction;
            }

            for (Element signatureElement : signatureElements) {
                verifyDomSignature(document, signatureElement);
                extractSignedReferences(signatureElement, extraction.getSignedElements());
            }

            @SuppressWarnings("unchecked")
            List<WSHandlerResultAdapter> adapted = (List<WSHandlerResultAdapter>) context.get("BANKING_WSS4J_RESULTS");
            if (adapted != null) {
                for (WSHandlerResultAdapter result : adapted) {
                    extraction.getSignedElements().addAll(result.getSignedElements());
                }
            }

            extraction.setSignatureVerified(true);
            deduplicate(extraction.getSignedElements());
            return extraction;
        } catch (Exception ex) {
            throw new BankingServiceFault("SIGNATURE_PROCESSING_ERROR", ex.getMessage());
        }
    }

    private static void deduplicate(List<String> values) {
        List<String> copy = new ArrayList<>();
        for (String v : values) {
            if (v != null && !copy.contains(v)) {
                copy.add(v);
            }
        }
        values.clear();
        values.addAll(copy);
    }

    private static Document parse(String xml) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        Document document = dbf.newDocumentBuilder()
                .parse(new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));
        markIds(document.getDocumentElement());
        return document;
    }

    private static void markIds(Element element) {
        if (element == null) {
            return;
        }
        if (element.hasAttribute("Id")) {
            element.setIdAttribute("Id", true);
        }
        if (element.hasAttributeNS(WSConstants.WSU_NS, "Id")) {
            element.setIdAttributeNS(WSConstants.WSU_NS, "Id", true);
        }
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node n = children.item(i);
            if (n instanceof Element) {
                markIds((Element) n);
            }
        }
    }

    private static List<Element> findSignatureElements(Document document) {
        NodeList nodeList = document.getElementsByTagNameNS(DS_NS, "Signature");
        List<Element> list = new ArrayList<>();
        for (int i = 0; i < nodeList.getLength(); i++) {
            Node node = nodeList.item(i);
            if (node instanceof Element) {
                list.add((Element) node);
            }
        }
        return list;
    }

    private static void verifyDomSignature(Document document, Element signatureElement) throws Exception {
        XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
        DOMValidateContext validateContext = new DOMValidateContext(new X509KeySelector(), signatureElement);
        markIds(document.getDocumentElement());
        boolean valid = factory.unmarshalXMLSignature(validateContext).validate(validateContext);
        if (!valid) {
            throw new BankingServiceFault("SIGNATURE_INVALID", "XML Signature validation failed");
        }
    }

    private static void extractSignedReferences(Element signatureElement, List<String> targets) {
        NodeList references = signatureElement.getElementsByTagNameNS(DS_NS, "Reference");
        for (int i = 0; i < references.getLength(); i++) {
            Node refNode = references.item(i);
            if (refNode instanceof Element) {
                Element ref = (Element) refNode;
                String uri = ref.getAttribute("URI");
                if (uri != null && !uri.isEmpty()) {
                    targets.add(uri);
                }
            }
        }
    }

    private static class X509KeySelector extends KeySelector {
        @Override
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose, AlgorithmMethod method, XMLCryptoContext context)
                throws KeySelectorException {
            if (keyInfo == null) {
                throw new KeySelectorException("No KeyInfo found");
            }
            for (Object info : keyInfo.getContent()) {
                XMLStructure xmlStructure = (XMLStructure) info;
                if (xmlStructure instanceof X509Data) {
                    X509Data x509Data = (X509Data) xmlStructure;
                    for (Object data : x509Data.getContent()) {
                        if (data instanceof X509Certificate) {
                            final X509Certificate cert = (X509Certificate) data;
                            return () -> cert.getPublicKey();
                        }
                    }
                } else if (xmlStructure instanceof KeyValue) {
                    try {
                        final java.security.PublicKey publicKey = ((KeyValue) xmlStructure).getPublicKey();
                        return () -> publicKey;
                    } catch (Exception ex) {
                        throw new KeySelectorException(ex);
                    }
                }
            }
            throw new KeySelectorException("No certificate or public key found in KeyInfo");
        }
    }
}

class WsSecurityServerInterceptor extends AbstractPhaseInterceptor<SoapMessage> {

    public WsSecurityServerInterceptor() {
        super(Phase.PRE_PROTOCOL);
    }

    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        try {
            SOAPMessage saaj = message.getContent(SOAPMessage.class);
            if (saaj == null) {
                return;
            }
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            saaj.writeTo(baos);
            Document document = DocumentBuilderFactory.newInstance().newDocumentBuilder()
                    .parse(new ByteArrayInputStream(baos.toByteArray()));

            RequestData requestData = new RequestData();
            requestData.setSigVerCrypto(CryptoFactoryHolder.signatureVerificationCrypto());

            WSSecurityEngine engine = new WSSecurityEngine();
            List<WSSecurityEngineResult> results = engine.processSecurityHeader(
                    document,
                    requestData
            );

            List<WSHandlerResultAdapter> adaptedResults = new ArrayList<>();
            if (results != null) {
                WSHandlerResultAdapter adapter = new WSHandlerResultAdapter();
                for (WSSecurityEngineResult result : results) {
                    Integer action = (Integer) result.get(WSSecurityEngineResult.TAG_ACTION);
                    if (action != null && action == WSConstants.SIGN) {
                        @SuppressWarnings("unchecked")
                        List<WSDataRef> dataRefs = (List<WSDataRef>) result.get(WSSecurityEngineResult.TAG_DATA_REF_URIS);
                        if (dataRefs != null) {
                            for (WSDataRef ref : dataRefs) {
                                if (ref.getProtectedElement() != null) {
                                    adapter.getSignedElements().add(ref.getProtectedElement().getNodeName());
                                }
                            }
                        }
                    }
                }
                adaptedResults.add(adapter);
            }
            message.put("BANKING_WSS4J_RESULTS", adaptedResults);
        } catch (Exception ex) {
            throw new Fault(ex);
        }
    }
}

